import heapq

def solve(n: int, edges: list[list[int]]) -> int:
    adj = [[] for _ in range(n)]
    for u, v, s, e in edges:
        adj[u].append((v, s, e))

    dist = [float('inf')] * n
    dist[0] = 0
    heap = [(0, 0)]

    while heap:
        current_time, current_node = heapq.heappop(heap)
        if current_node == n - 1:
            return current_time
        if current_time > dist[current_node]:
            continue
        for (v, s, e) in adj[current_node]:
            if current_time <= e:
                earliest = max(current_time, s)
                new_time = earliest + 1
                if new_time < dist[v]:
                    dist[v] = new_time
                    heapq.heappush(heap, (new_time, v))
    return -1
